class Solution {
    public boolean canChange(String start, String target) {
        if (start.length() != target.length()) {
            return false;
        }
        int left = 0;
        int right = start.length() - 1;
        while (left <= right) {
            if (start.charAt(left) == 'L' && target.charAt(left) == 'L' && start.charAt(left) != '_') {
                if (left > 0 && start.charAt(left - 1) == '_') {
                    left++;
                } else {
                    return false;
                }
            } else if (start.charAt(right) == 'R' && target.charAt(right) == 'R' && start.charAt(right) != '_') {
                if (right < start.length() - 1 && start.charAt(right + 1) == '_') {
                    right--;
                } else {
                    return false;
                }
            } else {
                left++;
                right--;
            }
        }
        return true;
    }
}
